const d = $json.payload || $json || {};
const safeArray = (value) => Array.isArray(value) ? value : [];
const safeObject = (value) => value && typeof value === 'object' && !Array.isArray(value) ? value : {};

function normalizeTask(t = {}) {
  return {
    ...t,
    nombre: t.nombre || t.name || 'Tarea sin nombre',
    lista: t.lista || 'Sin fase',
    responsables: safeArray(t.responsables),
    archivos: safeArray(t.archivos),
    enlaces: safeArray(t.enlaces),
    checklist_total: Number(t.checklist_total || 0),
    checklist_done: Number(t.checklist_done || 0),
    adjuntos_count: Number(t.adjuntos_count || 0),
    dias_sin_actividad: t.dias_sin_actividad ?? '-'
  };
}

function normalizePhase(f = {}) {
  const tareas = safeArray(f.tareas).map(normalizeTask);
  const completadas = Number(f.completadas ?? tareas.filter(t => t.completada).length);
  const total = Number(f.total ?? tareas.length);
  const vencidas = Number(f.vencidas ?? tareas.filter(t => t.vencida).length);
  const pendientes = Number(f.pendientes ?? Math.max(total - completadas - vencidas, 0));
  const pct = Number(f.pct ?? (total > 0 ? Math.round((completadas / total) * 100) : 0));
  return {
    ...f,
    nombre: f.nombre || f.name || 'Fase sin nombre',
    semaforo: f.semaforo || 'gris',
    tareas,
    completadas,
    total,
    vencidas,
    pendientes,
    pct
  };
}

d.fases = Object.fromEntries(Object.entries(safeObject(d.fases)).map(([key, value]) => [key, normalizePhase(value)]));
d.github = {
  commits_back: 0,
  commits_front: 0,
  prs_abiertos_back: 0,
  prs_abiertos_front: 0,
  top_commits_back: [],
  top_commits_front: [],
  ci_back: null,
  ci_front: null,
  deploy_front_url: '',
  ...safeObject(d.github)
};
d.github.top_commits_back = safeArray(d.github.top_commits_back);
d.github.top_commits_front = safeArray(d.github.top_commits_front);
d.kpis = {
  dias_hasta_fin: '-',
  proyeccion: 'sin datos',
  velocidad_tareas_por_dia: 0,
  completadas_7d: 0,
  silencio_back_dias: '-',
  silencio_front_dias: '-',
  pct_commits_convencionales: 0,
  bus_factor_14d: 0,
  pr_open_time_dias: 0,
  pr_merge_ratio_30d: 0,
  ...safeObject(d.kpis)
};
d.snapshot_tareas = safeArray(d.snapshot_tareas).map(normalizeTask);
d.ranking = safeArray(d.ranking);
d.cards_stale = safeArray(d.cards_stale).map(normalizeTask);
d.cards_sin_asignar = safeArray(d.cards_sin_asignar).map(normalizeTask);
d.cards_sin_fecha = safeArray(d.cards_sin_fecha).map(normalizeTask);
d.hitos_proximos = safeArray(d.hitos_proximos);
d.problemas_detectados = safeArray(d.problemas_detectados);
d.fecha = d.fecha || new Date().toISOString();
d.progreso_pct = Number(d.progreso_pct || 0);
d.total_completadas = Number(d.total_completadas || 0);
d.total_tarjetas = Number(d.total_tarjetas || 0);
d.tendencia_historial = d.tendencia_historial || 'sin historial suficiente';
d.severidad_max = d.severidad_max || 'baja';
d.cantidad_problemas = Number(d.cantidad_problemas || d.problemas_detectados.length || 0);

function semEmoji(s) { return ({ verde: '🟢', amarillo: '🟡', rojo: '🔴', gris: '⚪' })[s] || '⚪'; }

function renderFase(f) {
  const lines = [semEmoji(f.semaforo) + ' ' + f.nombre + ' (' + f.completadas + '/' + f.total + ' = ' + f.pct + '%)'];
  for (const t of safeArray(f.tareas)) {
    const status = t.completada ? '[✓]' : (t.vencida ? '[✗ VENCIDA]' : '[⏳]');
    const responsables = safeArray(t.responsables);
    const resp = responsables.length > 0 ? responsables.join(', ') : 'SIN ASIGNAR';
    const due = t.fecha_limite ? ' due=' + t.fecha_limite.slice(0, 10) : ' (sin fecha)';
    const chk = t.checklist_total > 0 ? ' checklist=' + t.checklist_done + '/' + t.checklist_total : '';
    const adj = t.adjuntos_count > 0 ? ' adj=' + t.adjuntos_count : '';
    lines.push('  ' + status + ' ' + t.nombre + ' -> ' + resp + due + chk + adj);
  }
  return lines.join('\n');
}

const fasesStr = Object.values(d.fases).map(renderFase).join('\n\n') || 'Sin fases registradas.';

const commitsBackStr = d.github.top_commits_back.map(c => '  ' + c.sha + ' ' + c.autor + ': ' + c.mensaje + ' (' + (c.fecha || '').slice(0, 10) + ')').join('\n') || '  (sin commits)';
const commitsFrontStr = d.github.top_commits_front.map(c => '  ' + c.sha + ' ' + c.autor + ': ' + c.mensaje + ' (' + (c.fecha || '').slice(0, 10) + ')').join('\n') || '  (sin commits)';

const entregables = d.snapshot_tareas
  .filter(t => (t.archivos.length > 0 || t.enlaces.length > 0) && t.nombre && t.nombre.trim() !== '.')
  .sort((a, b) => new Date(b.dateLastActivity || 0) - new Date(a.dateLastActivity || 0))
  .slice(0, 15)
  .map(t => {
    const files = t.archivos.map(a => a.name).join(', ');
    const links = t.enlaces.map(l => (l.name || l.url)).join(', ');
    const parts = [files, links].filter(Boolean).join(' | ');
    return '  [' + t.lista + '] ' + t.nombre + ': ' + parts;
  }).join('\n') || '  (ninguno)';

const rankingStr = d.ranking.map(r => '  ' + r.initials + ' ' + r.trello_name + ': ' + r.tareas_done + '✓ / ' + r.tareas_pending + '⏳ / ' + r.tareas_overdue + '✗   commits14d=' + r.commits_14d).join('\n') || '  (sin datos)';

const ciBack = d.github.ci_back ? d.github.ci_back.status + ' en ' + d.github.ci_back.branch + ' (' + (d.github.ci_back.date || '').slice(0, 10) + ')' : 'sin datos';
const ciFront = d.github.ci_front ? d.github.ci_front.status + ' en ' + d.github.ci_front.branch + ' (' + (d.github.ci_front.date || '').slice(0, 10) + ')' : 'sin datos';

function sign(n) { return n >= 0 ? '+' + n : String(n); }
const diffStr = d.diff_previa ? 'progreso ' + sign(d.diff_previa.progreso) + '% | vencidas ' + sign(d.diff_previa.vencidas) + ' | commits14d ' + sign(d.diff_previa.commits_14d) : 'sin previa';

const staleStr = d.cards_stale.slice(0, 5).map(t => t.nombre + '(' + t.dias_sin_actividad + 'd, ' + (safeArray(t.responsables)[0] || 'sin asignar') + ')').join(', ') || 'ninguna';
const sinAsignarStr = d.cards_sin_asignar.slice(0, 5).map(t => t.nombre).join(', ') || 'ninguna';
const sinFechaStr = d.cards_sin_fecha.slice(0, 5).map(t => t.nombre).join(', ') || 'ninguna';

const prompt = 'Eres gestor PM del proyecto PetSafe (clínica veterinaria, NestJS backend + Angular frontend, fin programado 2026-06-10). Analiza estado real y da diagnóstico accionable en español, texto plano, SIN markdown, SIN asteriscos, SIN emojis.\n\n' +
'Estructura OBLIGATORIA, cada sección máx 3 oraciones:\n' +
'RESUMEN: estado global (verde/amarillo/rojo) con motivo principal en una línea.\n' +
'POR FASE: comenta SOLO las fases con problemas o riesgo, menciona tareas específicas por nombre.\n' +
'CARGA EQUIPO: observación sobre distribución de trabajo entre FG, DM, DP, JA.\n' +
'RIESGOS: top 3 con severidad y causa (no inventes, usa los datos).\n' +
'ACCIONES: 3 acciones concretas asignadas por nombre real (ej: Josué revisar PR X, David Barragán desbloquear tarea Y).\n' +
'PROYECCION: llegamos al 10-jun-2026? sí/no/riesgo con justificación numérica.\n' +
'REPLANIFICACION: si detectas sobrecarga o bloqueos, sugiere explícitamente qué tareas mover al próximo sprint o a quién reasignar.\n\n' +
'=== CONTEXTO REAL ===\n' +
'Fecha: ' + d.fecha + '\n' +
'Progreso global: ' + d.progreso_pct + '% (' + d.total_completadas + '/' + d.total_tarjetas + ')\n' +
'Días hasta fin proyecto: ' + d.kpis.dias_hasta_fin + '\n' +
'Proyección calculada: ' + d.kpis.proyeccion + '\n' +
'Velocidad: ' + d.kpis.velocidad_tareas_por_dia + ' tareas/día (' + d.kpis.completadas_7d + ' completadas últimos 7d)\n' +
'Diff vs análisis previo: ' + diffStr + '\n' +
'Tendencia histórica: ' + d.tendencia_historial + '\n\n' +
'=== TAREAS POR FASE (completo) ===\n' +
fasesStr + '\n\n' +
'=== CARDS PROBLEMÁTICAS ===\n' +
'Stale (sin actividad >5d): ' + d.cards_stale.length + ' -> ' + staleStr + '\n' +
'Sin asignar: ' + d.cards_sin_asignar.length + ' -> ' + sinAsignarStr + '\n' +
'Sin fecha: ' + d.cards_sin_fecha.length + ' -> ' + sinFechaStr + '\n\n' +
'=== GITHUB ===\n' +
'Commits 14d back=' + d.github.commits_back + ' front=' + d.github.commits_front + '\n' +
'Silencio back=' + d.kpis.silencio_back_dias + 'd front=' + d.kpis.silencio_front_dias + 'd\n' +
'% commits convencionales (feat/fix/etc): ' + d.kpis.pct_commits_convencionales + '%\n' +
'Bus factor 14d (autores distintos): ' + d.kpis.bus_factor_14d + '\n' +
'PRs abiertos: ' + (d.github.prs_abiertos_back + d.github.prs_abiertos_front) + ' (avg ' + d.kpis.pr_open_time_dias + 'd open)\n' +
'CI backend: ' + ciBack + '\n' +
'CI frontend: ' + ciFront + '\n' +
'Deploy front: ' + d.github.deploy_front_url + '\n\n' +
'Top 5 commits backend:\n' + commitsBackStr + '\n\n' +
'Top 5 commits frontend:\n' + commitsFrontStr + '\n\n' +
'=== CARGA POR PERSONA ===\n' +
rankingStr + '\n\n' +
'=== ENTREGABLES (archivos + enlaces) ===\n' +
entregables + '\n\n' +
'=== HITOS PRÓXIMOS ===\n' +
(d.hitos_proximos.map(h => h.nombre + ' (' + h.dias_faltan + 'd, resp=' + h.responsable + ')').join('\n') || '(ninguno)') + '\n\n' +
'Problemas auto-detectados: ' + JSON.stringify(d.problemas_detectados) + '\n' +
'Severidad máxima: ' + d.severidad_max;

return [{ json: { prompt, gemini_key: d.gemini_key, discord_url: d.discord_url || '', analysis: d } }];

