d.progreso_pct = Number(d.progreso_pct || 0);
d.total_completadas = Number(d.total_completadas || 0);
d.total_tarjetas = Number(d.total_tarjetas || 0);
d.severidad_max = d.severidad_max || 'baja';
d.cantidad_problemas = Number(d.cantidad_problemas || d.problemas_detectados.length || 0);
const geminiResp = $node['Gemini Análisis'].json;
const iaText =
  geminiResp?.text ||
  geminiResp?.response?.generations?.[0]?.[0]?.text?.trim() ||
  geminiResp?.candidates?.[0]?.content?.parts?.[0]?.text?.trim() ||
  '(sin respuesta IA)';

const colorMap = { alta: 15158332, media: 16761095, baja: 3066993 };
const color = colorMap[d.severidad_max] || 3066993;
const fechaLocal = new Date(d.fecha || Date.now()).toLocaleDateString('es-EC', { timeZone: 'America/Guayaquil' });

function semEmoji(s) { return ({ verde: '🟢', amarillo: '🟡', rojo: '🔴', gris: '⚪' })[s] || '⚪'; }
function sign(n) { return n >= 0 ? '+' + n : String(n); }
function clean(value) { return String(value ?? '').replace(/\s+/g, ' ').trim(); }
function trim(value, max = 1000) {
  const text = String(value ?? '').trim();
  return text.length > max ? text.slice(0, max - 1) + '…' : text;
}
function field(name, value, inline = false) {
  return { name: trim(name, 256), value: trim(value || '-', 1024), inline };
}
function payload(title, description, fields, footer) {
  return {
    username: 'Monitor PetSafe',
    embeds: [{
      title: trim(title, 256),
      description: trim(description, 3900),
      color,
      fields: fields.filter(f => f && f.value && f.value !== '-').slice(0, 8),
      footer: { text: trim(footer || ('Monitor automatico · ' + String(d.severidad_max || 'baja').toUpperCase()), 2048) },
      timestamp: d.fecha || new Date().toISOString()
    }],
    allowed_mentions: { parse: [] }
  };
}
function dateShort(value) { return value ? String(value).slice(0, 10) : '-'; }
function shortName(value) { return String(value || '?').split(' ').filter(Boolean).slice(0, 2).join(' ') || '?'; }

function commitIntent(message) {
  const msg = String(message || '').toLowerCase();
  if (/merge pull request|merge branch|merge remote/.test(msg)) return '🔀 Integrado (Merge)';
  if (/fix|hotfix|bug|conflict|resolve/.test(msg)) return '🐛 Corregido / revisar regresion';
  if (/test|spec|coverage|queue/.test(msg)) return '🧪 Validacion tecnica';
  if (/feat|add|implement|create/.test(msg)) return '✨ Funcionalidad realizada';
  if (/refactor|cleanup|chore|build|ci/.test(msg)) return '🔧 Mantenimiento tecnico';
  if (/docs/.test(msg)) return '📝 Documentacion';
  if (/perf/.test(msg)) return '⚡ Optimizacion';
  return '🔨 Cambio tecnico';
}
function commitRisk(message) {
  const msg = String(message || '').toLowerCase();
  if (/conflict|hotfix|rollback|revert|failed|error/.test(msg)) return '🔴 pendiente de revisar';
  if (/test|coverage|fix/.test(msg)) return '🟡 verificar resultado';
  if (/merge pull request|merge branch|merge remote/.test(msg)) return '🟢 ya integrado';
  return '⚪ seguimiento normal';
}
function renderCommit(c) {
  const fullMsg = clean(c.mensaje || c.commit?.message || '');
  const msgLine = fullMsg.split('\n')[0];
  let modulo = '';
  const moduleMatch = msgLine.match(/^[a-z]+\(([^)]+)\):/i);
  if (moduleMatch && moduleMatch[1]) modulo = ' `[' + moduleMatch[1] + ']`';
  let prInfo = '';
  const prMatch = msgLine.match(/merge pull request #(\d+)/i) || msgLine.match(/\(#(\d+)\)/);
  if (prMatch && prMatch[1]) prInfo = ' **(PR #' + prMatch[1] + ')**';
  return '`' + (c.sha || '').slice(0, 7) + '` **' + shortName(c.autor) + '**' + modulo + prInfo + ' · ' + commitIntent(msgLine) + '\n  └─ ' + trim(msgLine, 110) + ' · ' + dateShort(c.fecha) + ' · _' + commitRisk(msgLine) + '_';
}
function renderCommits(list) {
  if (!list || list.length === 0) return '(sin commits recientes)';
  const autores = {};
  list.forEach(c => { const autor = shortName(c.autor); autores[autor] = (autores[autor] || 0) + 1; });
  const ranking = Object.entries(autores).sort((a, b) => b[1] - a[1]).map(([autor, count]) => autor + ' (' + count + ')').join(', ');
  const lines = list.slice(0, 5).map(renderCommit);
  return '**Top Activos**: ' + ranking + '\n\n' + lines.join('\n');
}

const resumen1 = semEmoji(d.severidad_max === 'alta' ? 'rojo' : d.severidad_max === 'media' ? 'amarillo' : 'verde') + ' **' + d.progreso_pct + '%** progreso · ' + d.total_completadas + '/' + d.total_tarjetas + ' tareas · **' + d.kpis.dias_hasta_fin + 'd** hasta fin';
const resumen2 = '📈 Proyección: **' + d.kpis.proyeccion + '** · Velocidad ' + d.kpis.velocidad_tareas_por_dia + '/día · ' + d.kpis.completadas_7d + ' completadas últimos 7d';
const resumen3 = d.diff_previa ? '🔁 vs previa: ' + sign(d.diff_previa.progreso) + '% progreso, ' + sign(d.diff_previa.vencidas) + ' vencidas, ' + sign(d.diff_previa.commits_14d) + ' commits' : '🔁 primera ejecución';
const headerDescription = [resumen1, resumen2, resumen3].join('\n');

const kpiTxt = '⚡ Velocidad: ' + d.kpis.velocidad_tareas_por_dia + '/día · Bus factor: ' + d.kpis.bus_factor_14d + ' · Conv: ' + d.kpis.pct_commits_convencionales + '%\n' +
  '🔇 Silencio back: ' + d.kpis.silencio_back_dias + 'd · front: ' + d.kpis.silencio_front_dias + 'd\n' +
  '🔀 PRs abiertos: ' + (d.github.prs_abiertos_back + d.github.prs_abiertos_front) + ' · avg open ' + d.kpis.pr_open_time_dias + 'd · merge ratio ' + d.kpis.pr_merge_ratio_30d + '%';

const problemasTxt = (d.problemas_detectados || []).length
  ? d.problemas_detectados.map(p => '• ' + p.tipo + ' · severidad ' + p.severidad + (p.count ? ' · ' + p.count : '')).join('\n')
  : 'Sin problemas automáticos críticos.';

const faseBlocks = Object.values(d.fases || {}).map(f => {
  const head = semEmoji(f.semaforo) + ' **' + f.nombre + '** ' + f.pct + '% (✓' + f.completadas + ' ⏳' + f.pendientes + ' ✗' + f.vencidas + ')';
  const problemTasks = (f.tareas || [])
    .filter(t => t.nombre && t.nombre.trim() !== '.' && (!t.completada || t.vencida || t.stale || t.sin_asignar))
    .slice(0, 6)
    .map(t => {
      const ic = t.completada ? '✓' : (t.vencida ? '🔴' : '⏳');
      const r = t.responsables?.[0] ? ' · ' + shortName(t.responsables[0]) : ' · sin asignar';
      const due = t.fecha_limite ? ' · ' + dateShort(t.fecha_limite) : '';
      return ic + ' ' + trim(t.nombre, 56) + r + due;
    });
  return head + (problemTasks.length ? '\n' + problemTasks.join('\n') : '\nSin pendientes relevantes en esta fase.');
});

const problematicLines = [];
if ((d.cards_stale || []).length > 0) problematicLines.push('🕸️ **Stale**: ' + d.cards_stale.slice(0, 5).map(t => trim(t.nombre, 42) + '(' + t.dias_sin_actividad + 'd)').join(', '));
if ((d.cards_sin_asignar || []).length > 0) problematicLines.push('❓ **Sin asignar**: ' + d.cards_sin_asignar.slice(0, 5).map(t => trim(t.nombre, 42)).join(', '));
if ((d.cards_sin_fecha || []).length > 0) problematicLines.push('📅 **Sin fecha**: ' + d.cards_sin_fecha.slice(0, 5).map(t => trim(t.nombre, 42)).join(', '));

const entregables = (d.snapshot_tareas || [])
  .filter(t => ((t.archivos || []).length > 0 || (t.enlaces || []).length > 0) && t.nombre && t.nombre.trim() !== '.')
  .sort((a, b) => new Date(b.dateLastActivity || 0) - new Date(a.dateLastActivity || 0))
  .slice(0, 6);
const entregablesTxt = entregables.length ? entregables.map(t => {
  const files = (t.archivos || []).slice(0, 2).map(a => '[📄 ' + trim(a.name, 45) + '](' + a.url + ')').join(' ');
  const links = (t.enlaces || []).slice(0, 2).map(l => '[🔗 ' + trim(l.name || 'link', 45) + '](' + l.url + ')').join(' ');
  return '**' + trim(t.nombre, 48) + '**: ' + [files, links].filter(Boolean).join(' ');
}).join('\n') : 'Sin entregables recientes con adjuntos/enlaces.';

const ciStatusEmoji = s => s === 'success' ? '✅' : s === 'failure' ? '❌' : s === 'in_progress' ? '🟡' : '⚪';
const ciBackTxt = d.github.ci_back ? ciStatusEmoji(d.github.ci_back.status) + ' ' + d.github.ci_back.status + ' · `' + d.github.ci_back.branch + '` · [run](' + d.github.ci_back.url + ')' : '(sin datos)';
const ciFrontTxt = d.github.ci_front ? ciStatusEmoji(d.github.ci_front.status) + ' ' + d.github.ci_front.status + ' · `' + d.github.ci_front.branch + '` · [run](' + d.github.ci_front.url + ')' : '(sin datos)';

const hitTxt = (d.hitos_proximos || []).length
  ? d.hitos_proximos.slice(0, 5).map(h => '📅 **' + h.nombre + '** en ' + h.dias_faltan + 'd (' + h.responsable + ')').join('\n')
  : 'Sin hitos próximos registrados.';

function chunkText(text, size = 950) {
  const lines = String(text || '').split('\n');
  const chunks = [];
  let current = '';
  for (const line of lines) {
    if ((current + '\n' + line).length > size && current) {
      chunks.push(current);
      current = line;
    } else {
      current = current ? current + '\n' + line : line;
    }
  }
  if (current) chunks.push(current);
  return chunks.length ? chunks : ['(sin contenido)'];
}

const messages = [];
messages.push(payload(
  '📊 Estado proyecto PetSafe — ' + fechaLocal + ' · Resumen',
  headerDescription,
  [field('Resumen de riesgo', problemasTxt), field('KPIs PMO', kpiTxt)],
  'Monitor automatico · ' + String(d.severidad_max || 'baja').toUpperCase() + ' · ' + d.cantidad_problemas + ' problemas'
));

const faseChunks = chunkText(faseBlocks.join('\n\n'), 950);
faseChunks.slice(0, 3).forEach((chunk, idx) => {
  messages.push(payload(
    '📋 Tareas por fase' + (faseChunks.length > 1 ? ' · bloque ' + (idx + 1) : ''),
    'Fases con pendientes, vencidas o señales de seguimiento.',
    [field('Fases', chunk), problematicLines.length ? field('Cards problemáticas', problematicLines.join('\n')) : null],
    'Se priorizan tareas no completadas, stale o sin asignar.'
  ));
});

messages.push(payload(
  '🧾 Actividad técnica interpretada',
  'Los commits se resumen con intención PM: qué parece realizado y qué queda para verificar.',
  [
    field('Backend', renderCommits(d.github.top_commits_back)),
    field('Frontend', renderCommits(d.github.top_commits_front))
  ],
  'Fuente: últimos commits recolectados por el monitor.'
));

messages.push(payload(
  '🚦 Entregables, CI e hitos',
  'Estado de evidencia entregable y señales de integración.',
  [
    field('Entregables recientes', entregablesTxt),
    field('CI / Deploy', 'Backend: ' + ciBackTxt + '\nFrontend: ' + ciFrontTxt + '\n🌐 Deploy front: ' + d.github.deploy_front_url),
    field('Hitos próximos', hitTxt)
  ],
  'Revisar CI fallido o ausencia de datos antes de cerrar entregables.'
));

chunkText(iaText, 950).slice(0, 4).forEach((chunk, idx, arr) => {
  messages.push(payload(
    '🤖 Diagnóstico IA' + (arr.length > 1 ? ' · bloque ' + (idx + 1) : ''),
    'Análisis narrativo de Gemini sobre riesgos, carga y acciones.',
    [field('Diagnóstico', chunk)],
    'Diagnóstico IA guardado también en analisis_proyecto.recomendaciones_ia.'
  ));
});

return [{
  json: {
    discord_payload: messages[0],
    discord_messages: messages,
    ia_text: iaText,
    discord_url: $node['Preparar Prompt'].json.discord_url || '',
    monitor_summary: headerDescription,
    message_count: messages.length
  }
}];

