const messages = Array.isArray($json.discord_messages) ? $json.discord_messages : [$json.discord_payload].filter(Boolean);
return messages.map((payload, index) => ({
  json: {
    discord_payload: payload,
    discord_url: $json.discord_url || '',
    ia_text: $json.ia_text,
    monitor_summary: $json.monitor_summary,
    message_index: index + 1,
    message_count: messages.length
  }
}));
